Adaptive parallel evaluation with multi-criteria scoring and dynamic route activation, prioritizing minimal marginal cost increase while considering temporal feasibility, spatial proximity, and capacity constraints through weighted composite scores, falling back to safest feasible insertion when no positive score exists.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    const wCost = 0.6
    const wTime = 0.25
    const wDist = 0.15
    type candidate struct {
        assignIdx int
        oldCost   float64
        newCost   float64
        feasible  bool
        timeScore float64
        distScore float64
        composite float64
    }
    orderIndices := make([]int, len(oris))
    for i := range orderIndices {
        orderIndices[i] = i
    }
    rand.Shuffle(len(orderIndices), func(i, j int) {
        orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
    })
    nextNewIdx := dispatch.AssignsLen
    for _, idx := range orderIndices {
        var cands []candidate
        for aIdx := 0; aIdx < nextNewIdx; aIdx++ {
            oldCost := dispatch.Assigns[aIdx].Cost
            ok := dispatch.Assigns[aIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
            if !ok {
                dispatch.Assigns[aIdx].RemoveShip(total_ship + idx)
                continue
            }
            dispatch.Assigns[aIdx].GenRoute()
            newCost := dispatch.Assigns[aIdx].Cost
            feasible := newCost >= 0
            var timeScore, distScore float64
            if feasible {
                delta := newCost - oldCost
                maxAllowed := 100000.0
                if delta < 0 {
                    timeScore = 1.0
                } else if delta > maxAllowed {
                    timeScore = 0.0
                } else {
                    timeScore = 1.0 - (delta / maxAllowed)
                }
                d := cal_dis(oris[idx], dispatch.Assigns[aIdx].StationCurrent)
                distScore = 1.0 / (1.0 + d/100.0)
            }
            composite := 0.0
            if feasible {
                deltaNorm := (newCost - oldCost) / (1.0 + newCost)
                composite = wCost*(1.0/(1.0+deltaNorm)) + wTime*timeScore + wDist*distScore
            }
            cands = append(cands, candidate{
                assignIdx: aIdx,
                oldCost:   oldCost,
                newCost:   newCost,
                feasible:  feasible,
                timeScore: timeScore,
                distScore: distScore,
                composite: composite,
            })
            dispatch.Assigns[aIdx].RemoveShip(total_ship + idx)
            dispatch.Assigns[aIdx].GenRoute()
        }
        bestIdx := -1
        bestComposite := -1e9
        for _, cd := range cands {
            if cd.feasible && cd.composite > bestComposite {
                bestComposite = cd.composite
                bestIdx = cd.assignIdx
            }
        }
        if bestIdx == -1 {
            safeIdx := -1
            minPenalty := 1e18
            currentOri := oris[idx]
            for aIdx := 0; aIdx < dispatch.AssignsLen; aIdx++ {
                ok := dispatch.Assigns[aIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
                if ok {
                    dispatch.Assigns[aIdx].GenRoute()
                    if dispatch.Assigns[aIdx].Cost >= 0 {
                        penalty := cal_dis(currentOri, dispatch.Assigns[aIdx].StationCurrent)
                        if penalty < minPenalty {
                            minPenalty = penalty
                            safeIdx = aIdx
                        }
                    }
                    dispatch.Assigns[aIdx].RemoveShip(total_ship + idx)
                    dispatch.Assigns[aIdx].GenRoute()
                }
            }
            if safeIdx != -1 {
                bestIdx = safeIdx
            } else if nextNewIdx < MAXASSIGNS {
                bestIdx = nextNewIdx
            }
        }
        if bestIdx >= 0 && bestIdx < MAXASSIGNS {
            ok := dispatch.Assigns[bestIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
            if ok {
                dispatch.Assigns[bestIdx].GenRoute()
                if dispatch.Assigns[bestIdx].Cost >= 0 {
                    if bestIdx >= dispatch.AssignsLen {
                        dispatch.AssignsLen = bestIdx + 1
                        if bestIdx >= nextNewIdx {
                            nextNewIdx = bestIdx + 1
                        }
                    }
                } else {
                    dispatch.Assigns[bestIdx].RemoveShip(total_ship + idx)
                    dispatch.Assigns[bestIdx].GenRoute()
                    if nextNewIdx < MAXASSIGNS {
                        ok2 := dispatch.Assigns[nextNewIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
                        if ok2 {
                            dispatch.Assigns[nextNewIdx].GenRoute()
                            if dispatch.Assigns[nextNewIdx].Cost >= 0 {
                                dispatch.AssignsLen = nextNewIdx + 1
                                nextNewIdx++
                            } else {
                                dispatch.Assigns[nextNewIdx].RemoveShip(total_ship + idx)
                                dispatch.Assigns[nextNewIdx].GenRoute()
                            }
                        }
                    }
                }
            } else if nextNewIdx < MAXASSIGNS {
                ok3 := dispatch.Assigns[nextNewIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
                if ok3 {
                    dispatch.Assigns[nextNewIdx].GenRoute()
                    if dispatch.Assigns[nextNewIdx].Cost >= 0 {
                        dispatch.AssignsLen = nextNewIdx + 1
                        nextNewIdx++
                    } else {
                        dispatch.Assigns[nextNewIdx].RemoveShip(total_ship + idx)
                        dispatch.Assigns[nextNewIdx].GenRoute()
                    }
                }
            }
        } else if nextNewIdx < MAXASSIGNS {
            ok4 := dispatch.Assigns[nextNewIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
            if ok4 {
                dispatch.Assigns[nextNewIdx].GenRoute()
                if dispatch.Assigns[nextNewIdx].Cost >= 0 {
                    dispatch.AssignsLen = nextNewIdx + 1
                    nextNewIdx++
                } else {
                    dispatch.Assigns[nextNewIdx].RemoveShip(total_ship + idx)
                    dispatch.Assigns[nextNewIdx].GenRoute()
                }
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

